previewCss:
.darma-loader-darma-research-hologram-scan-cube { --speed: var(--loader-speed, 1s); --accent: var(--loader-color, #22d3ee); --accent-2: var(--loader-secondary-color, #a3e635); width: var(--loader-size, 88px); height: var(--loader-size, 88px); display: grid; place-items: center; position: relative; perspective: 550px; }
.darma-loader-darma-research-hologram-scan-cube__cube { width: 44%; height: 44%; position: relative; transform-style: preserve-3d; animation: darma-loader-darma-research-hologram-scan-cube-holo-turn calc(var(--speed) * 3) linear infinite; }
.darma-loader-darma-research-hologram-scan-cube__cube i, .darma-loader-darma-research-hologram-scan-cube__cube::before, .darma-loader-darma-research-hologram-scan-cube__cube::after { content: ""; position: absolute; inset: 0; border: 2px solid var(--accent); background: color-mix(in srgb, var(--accent) 12%, transparent); box-shadow: inset 0 0 18px color-mix(in srgb, var(--accent-2) 45%, transparent), 0 0 16px var(--accent); }
.darma-loader-darma-research-hologram-scan-cube__cube::before { transform: rotateY(90deg) translateZ(calc(var(--loader-size, 88px) * .22)); } .darma-loader-darma-research-hologram-scan-cube__cube::after { transform: rotateX(90deg) translateZ(calc(var(--loader-size, 88px) * .22)); }
.darma-loader-darma-research-hologram-scan-cube__cube i:nth-child(1) { transform: translateZ(calc(var(--loader-size, 88px) * .22)); } .darma-loader-darma-research-hologram-scan-cube__cube i:nth-child(2) { transform: translateZ(calc(var(--loader-size, 88px) * -.22)); } .darma-loader-darma-research-hologram-scan-cube__cube i:nth-child(3) { transform: rotateY(90deg) translateZ(calc(var(--loader-size, 88px) * -.22)); }
.darma-loader-darma-research-hologram-scan-cube__scan { position: absolute; width: 74%; height: 5%; border-radius: 999px; background: var(--accent-2); box-shadow: 0 0 18px 4px var(--accent-2); animation: darma-loader-darma-research-hologram-scan-cube-holo-scan calc(var(--speed) * 1.6) ease-in-out infinite; }
@keyframes darma-loader-darma-research-hologram-scan-cube-holo-turn { to { transform: rotateX(360deg) rotateY(360deg); } }
@keyframes darma-loader-darma-research-hologram-scan-cube-holo-scan { 0%,100% { transform: translateY(calc(var(--loader-size, 88px) * -.36)); opacity: .25; } 50% { transform: translateY(calc(var(--loader-size, 88px) * .36)); opacity: 1; } }

